// Normaliza as linhas da planilha para o formato que o painel (assets/js/parcerias-data.js) espera.

const STATUS_GRUPO = {
  '01': 'Planejamento', '02': 'Planejamento',
  '03': 'Diligência', '04': 'Diligência', '05': 'Diligência',
  '06': 'Parecer/Autorização', '07': 'Parecer/Autorização', '08': 'Parecer/Autorização',
  '09': 'Assinatura', '10': 'Assinatura', '11': 'Assinatura', '12': 'Assinatura',
  '13': 'Finalizado'
};

function grupoFromStatus(status) {
  if (!status) return 'Sem informação';
  const m = String(status).trim().match(/^(\d{2})/);
  return (m && STATUS_GRUPO[m[1]]) || 'Sem informação';
}

function toBool(v) {
  if (typeof v === 'boolean') return v;
  const s = String(v || '').trim().toLowerCase();
  return s === 'sim' || s === 'true' || s === '1' || s === 'x' || s === 'urgente';
}

function pick(obj, keys) {
  for (const k of keys) {
    if (obj[k] !== undefined && obj[k] !== null && obj[k] !== '') return obj[k];
  }
  return null;
}

function excelDateToStr(v) {
  if (v === null || v === undefined || v === '') return null;
  if (typeof v === 'number') {
    const ms = Math.round((v - 25569) * 86400 * 1000);
    const d = new Date(ms);
    const dd = String(d.getUTCDate()).padStart(2, '0');
    const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
    const yyyy = d.getUTCFullYear();
    return dd + '/' + mm + '/' + yyyy;
  }
  return String(v);
}

function pickAndamento(obj) {
  for (const k of Object.keys(obj)) {
    if (/manifesta/i.test(k) && obj[k]) return obj[k];
  }
  return pick(obj, ['Andamento', 'andamento']) || '';
}

return items.map((item) => {
  const r = item.json;
  const status = pick(r, ['Status', 'status', 'Etapa', 'etapa']) || '';
  const grupo = pick(r, ['Grupo', 'grupo']) || grupoFromStatus(status);
  const ordemRaw = pick(r, ['Ordem Numérica', 'Ordem', 'ordem', 'Nº', 'N°', 'Numero']);

  return {
    json: {
      ordem: ordemRaw != null && ordemRaw !== '' ? Number(ordemRaw) : null,
      dataRec: excelDateToStr(pick(r, ['Data recebimento da demanda na COCCS', 'Data Rec.', 'Data Recebimento', 'dataRec', 'Data'])),
      processo: pick(r, ['N° Processo Administrativo', 'Nº Processo Administrativo', 'Processo', 'processo']) || '',
      objeto: pick(r, ['Objeto', 'objeto']) || '',
      partes: pick(r, ['Partes', 'partes']) || '',
      demandante: pick(r, ['Demandante', 'demandante']) || 'Sem informação',
      status: status || 'Sem informação',
      grupo: grupo,
      urgente: toBool(pick(r, ['Urgência', 'urgência', 'Urgente', 'urgente'])),
      tipo: pick(r, ['Tipo', 'tipo']) || 'Sem informação',
      tipoInstr: pick(r, ['Tipo de instrumento', 'Tipo de Instrumento', 'Tipo Instrumento', 'tipoInstr', 'Instrumento']) || 'Sem informação',
      andamento: pickAndamento(r)
    }
  };
});
